const src = ($json.body !== undefined && $json.body !== null) ? $json.body : $json;
const d = typeof src === 'string' ? JSON.parse(src) : src;
return [{
  json: {
    keyword: d.keyword || '',
    job_id: d.job_id || '',
    user_id: d.user_id || '',
    company_name: d.company_name || '',
    services: d.services || '',
    tone_nl: d.tone_nl || '',
    locale: d.locale || '',
    userToken: d.userToken || '',
    xml_template: d.xml_template || '',
    xml_template_name: d.xml_template_name || '',
    content_goal: d.content_goal || 'convince'
  }
}];

const d = $json;
let xml = d.xml_template || '';
const goal = d.content_goal || 'convince';

xml = xml.replace(/<instructions>[\s\S]*?<\/instructions>/g, '');
xml = xml.replace(/<validation-checklist>[\s\S]*?<\/validation-checklist>/g, '');
xml = xml.replace(/```[\s\S]*?```/g, m => m.replace(/^```\n?/, '').replace(/\n?```$/, ''));
xml = xml.replace(/\n{3,}/g, '\n\n').trim();

const goalInstructions = {
  inform: 'Dit is een INFORMATIEVE pagina. Leg helder uit wat het onderwerp is, hoe het werkt en waarom het relevant is. Schrijf voor iemand die zich nog oriënteert. Geen verkooppraatje. Gebruik concrete feiten, voorbeelden en uitleg. Structuur: inleiding, uitleg, veelgestelde vragen.',
  convince: 'Dit is een OVERTUIGENDE dienstenpagina. De lezer vergelijkt aanbieders en overweegt een keuze. Laat zien waarom klanten kiezen voor ' + (d.company_name || 'dit bedrijf') + '. Focus op aantoonbare voordelen, expertise, kwaliteitsbewijzen en concrete resultaten voor de klant. Geen generieke claims — onderbouw elk voordeel.',
  convert: 'Dit is een CONVERSIEPAGINA. De lezer is klaar om te beslissen. Gebruik social proof, specifieke resultaten, garanties en een duidelijke call-to-action. Verwijder twijfels. Maak de volgende stap (aanvragen, contact opnemen) zo laagdrempelig mogelijk. Elk onderdeel moet bijdragen aan de beslissing om te kiezen.'
};

const variantInstructions = [
  'Variant 1: schrijf gebalanceerd en allround.',
  'Variant 2: maak de toon iets directer en overtuigender.',
  'Variant 3: maak de toon inhoudelijker en expertmatiger.',
  'Variant 4: maak de tekst praktischer en concreter met heldere stappen.',
  'Variant 5: maak de tekst commerciëler met sterke voordelen en resultaten.',
  'Variant 6: maak de tekst rustiger, toegankelijker en duidelijker.',
  'Variant 7: gebruik een meer onderscheidende invalshoek met scherpere positionering.',
  'Variant 8: maak de tekst compacter en scanbaarder voor drukke beslissers.',
  'Variant 9: maak de tekst meer case-gedreven en bewijsgericht.'
];

const goalInstruction = goalInstructions[goal] || goalInstructions.convince;

let userContent = "Schrijf 9 verschillende SEO-varianten over het zoekwoord: '" + d.keyword + "'.\n\n"
  + "Bedrijfsnaam: " + d.company_name + "\n"
  + "Services: " + d.services + "\n"
  + "Toon: " + d.tone_nl + "\n\n"
  + "PAGINADOEL:\n" + goalInstruction + "\n\n"
  + "MAAK EXACT 9 DUIDELIJK ONDERSCHEIDENDE VARIANTEN. Elke variant moet een eigen titel, meta description en volledige HTML-content hebben. Gebruik dezelfde feitelijke basis, maar varieer in invalshoek, ritme, formulering en nadruk.\n\n"
  + "VARIANT-RICHTINGEN:\n" + variantInstructions.join('\n');

if (xml) {
  userContent += '\n\n---\nGEBRUIK HET VOLGENDE XML-SJABLOON ALS STRIKTE STRUCTUUR voor de HTML output.\n\nBELANGRIJKE REGELS:\n1. Vervang alle placeholders zoals [dienstnaam] en [koopmotief] met echte content op basis van het zoekwoord en bedrijfsinfo.\n2. De <instruction> tags zijn schrijfinstructies voor jou — volg ze op maar neem ze NIET op in je output.\n3. Neem de XML-tags NIET letterlijk over in je HTML output. Gebruik ze alleen als structuurgids.\n4. Schrijf uitsluitend echte, geschreven content — geen template-tekst, geen regels, geen instructies.\n5. De content in je JSON moet puur HTML zijn: h1, h2, h3, p, ul, li — geen XML, geen template tags.\n\nSJABLOON:\n' + xml + '\n---';
} else {
  userContent += '\n\nGebruik H2 en H3 koppen, een sterke intro en concrete informatie.';
}

userContent += '\n\nGeef terug als JSON met exact dit formaat:\n{\n  "variants": [\n    { "title": string, "meta_description": string, "content": string },\n    ... totaal 9 objecten ...\n  ]\n}\n\nRetourneer geen extra tekst buiten het JSON-object.';

const body = {
  model: 'gpt-4o-mini',
  messages: [
    {
      role: 'system',
      content: 'Je bent een Nederlandse SEO content expert gespecialiseerd in B2B dienstverlening. Schrijf uitgebreide, goed gestructureerde paginas in het Nederlands. Retourneer altijd geldig JSON. Lever exact 9 inhoudelijk verschillende varianten aan en neem nooit instructietekst, XML-template-regels of validatiechecklist op in je output.'
    },
    {
      role: 'user',
      content: userContent
    }
  ],
  response_format: { type: 'json_object' }
};

return [{ json: { ...d, openai_body: body } }];

const resp = $json;
let article;
try {
  article = JSON.parse(resp.choices[0].message.content);
} catch(e) {
  article = { variants: [{ title: 'Artikel', content: resp.choices[0].message.content, meta_description: '' }] };
}

const rawVariants = Array.isArray(article.variants) ? article.variants : [];
const variants = rawVariants.slice(0, 9).map((variant, idx) => {
  const content = variant.content || '';
  const wordCount = content ? content.replace(/<[^>]*>/g, ' ').trim().split(/\s+/).filter(Boolean).length : 0;
  return {
    id: variant.id || ('variant-' + (idx + 1)),
    title: variant.title || ('Variant ' + (idx + 1)),
    meta_description: variant.meta_description || '',
    content: content,
    word_count: wordCount,
    seo_score: variant.seo_score || 84
  };
});

let jobId = '', keyword = '', userId = '';
const tryNodes = ['Build Prompt','Build Prompt1','Parse Payload','Parse Payload1','ContentFlow Webhook','ContentFlow Webhook1'];
for (const n of tryNodes) {
  try {
    const d = $(n).first().json;
    if (!jobId) jobId = d.job_id || d.query?.job_id || '';
    if (!keyword) keyword = d.keyword || '';
    if (!userId) userId = d.user_id || '';
    if (jobId && keyword && userId) break;
  } catch(e) {}
}

const primary = variants[0] || { title: '', meta_description: '', content: '', word_count: 0, seo_score: 84 };

return [{
  json: {
    job_id: jobId,
    keyword: keyword,
    user_id: userId,
    title: primary.title || '',
    content: primary.content || '',
    meta_description: primary.meta_description || '',
    variants: variants,
    patch_body: {
      status: 'done',
      result: {
        title: primary.title || '',
        content: primary.content || '',
        meta_description: primary.meta_description || '',
        variants: variants
      }
    }
  }
}];
